import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class ScratchPad {

    static class Interval {
        int start;
        int end;

        Interval(int start, int end) {
            this.start = start;
            this.end = end;
        }

        @Override
        public String toString() {
            return "[" + start + ", " + end + "]";
        }
    }

    private static List<Interval> subtractIntervals(List<Interval> intervals, List<Interval> subtractions) {
        List<Interval> result = new ArrayList<>();
        for (Interval interval : intervals) {
            int start = interval.start;
            int end = interval.end;

            for (Interval sub : subtractions) {
                if (sub.end < start) {
                    continue; // Subtraction interval ends before the current interval starts
                }

                if (sub.start > end) {
                    break; // Subtraction interval starts after the current interval ends
                }

                if (sub.start == start) {
                    start = sub.end + 1;
                } else if (sub.start > start && sub.start <= end) {
                    result.add(new Interval(start, sub.start - 1));
                    start = sub.end + 1;
                } else if (sub.end < end) {
                    start = sub.end + 1;
                } else if (sub.end == end) {
                    start = end + 1;
                    break;
                }
            }

            if (start <= end) {
                result.add(new Interval(start, end));
            }
        }

        return result;
    }


    public static void main(String[] args) {
        List<Interval> a = Arrays.asList(new Interval(1, 5), new Interval(7, 10), new Interval(12, 14));
        List<Interval> b = Arrays.asList(new Interval(2, 6), new Interval(10, 10));

        List<Interval> diff = subtractIntervals(a, b);
        for (Interval interval : diff) {
            System.out.println(interval);
        }
    }
}
